# OEIS sequence: A397335

def a(n):
    states = {1}
    for k in range(1, n+1):
        new_states = set(states)
        limit = 2**k
        for P in states:
            Q = P*(k+1)
            if Q <= limit:
                new_states.add(Q)
        states = new_states
    return len(states)
print([a(n) for n in range(46)])

